mapper.update:
UPDATE emission_record
record_date = #{recordDate}, process_id = #{processId}, material_energy_id = #{materialEnergyId}, consume_value = #{consumeValue}, emission_factor = #{emissionFactor}, emission_value = #{emissionValue}, audit_status = #{auditStatus},
WHERE id = #{id}

mapper.select:
SELECT DATE_FORMAT(record_date, '%Y-%m') as month, SUM(emission_value) as totalEmission FROM emission_record WHERE YEAR(record_date) = #{year}
AND MONTH(record_date) = #{month}
GROUP BY DATE_FORMAT(record_date, '%Y-%m') ORDER BY month

SELECT COALESCE(SUM(emission_value), 0)
FROM emission_record
WHERE record_date BETWEEN #{startDate} AND #{endDate}
